AND EXISTS ( SELECT 1 FROM article_tags at JOIN tags t ON t.id = at.tag_id WHERE at.article_id = a.id AND (LOWER(t.slug) = LOWER(#{tag}) OR LOWER(t.name) = LOWER(#{tag})) )
